import javax.management.*;
import javax.management.monitor.CounterMonitor;
import java.lang.management.ManagementFactory;

public class CounterMonitorUsage {
    public static void main(String[] args) throws Exception {
        MBeanServer mbs = ManagementFactory.getPlatformMBeanServer();

        // A simple MBean to be observed
        ObjectName observedObjectName = new ObjectName("com.example:type=ResourceUsage");
        ResourceUsage observedMBean = new ResourceUsage();
        mbs.registerMBean(observedMBean, observedObjectName);

        // Create and register the CounterMonitor
        ObjectName monitorObjectName = new ObjectName("com.example:type=MyCounterMonitor");
        CounterMonitor counterMonitor = new CounterMonitor();
        mbs.registerMBean(counterMonitor, monitorObjectName);

        // Configure the CounterMonitor
        counterMonitor.addObservedObject(observedObjectName);
        counterMonitor.setObservedAttribute("RequestCount");
        counterMonitor.setGranularityPeriod(500L); // Check every 500ms
        counterMonitor.setThreshold(new Long(5)); // Trigger when count reaches 5
        counterMonitor.setNotify(true);
        counterMonitor.setDifferenceMode(false); // Monitor absolute value

        // Add a notification listener
        counterMonitor.addNotificationListener((notification, handback) -> {
            System.out.println("CounterMonitor Notification: " + notification.getMessage());
        }, null, null);

        // Start the monitor
        counterMonitor.start();
        System.out.println("Monitor started. Incrementing counter...");

        // Simulate activity
        for (int i = 0; i < 10; i++) {
            Thread.sleep(300);
            observedMBean.incrementRequestCount();
            System.out.println("Current Request Count: " + observedMBean.getRequestCount());
        }

        counterMonitor.stop();
        mbs.unregisterMBean(monitorObjectName);
        mbs.unregisterMBean(observedObjectName);
    }

    public interface ResourceUsageMBean {
        Long getRequestCount();
        void incrementRequestCount();
    }

    public static class ResourceUsage implements ResourceUsageMBean {
        private Long requestCount = 0L;
        @Override public Long getRequestCount() { return requestCount; }
        @Override public synchronized void incrementRequestCount() { requestCount++; }
    }
}

