import javax.management.MBeanServer;
import javax.management.MBeanServerFactory;
import javax.management.ObjectName;
import javax.management.monitor.StringMonitor;

public class MonitorContainsExample {
    public static void main(String[] args) throws Exception {
        MBeanServer mbs = MBeanServerFactory.createMBeanServer();

        ObjectName mbeanName = new ObjectName("com.example:type=MyService,name=Status");
        mbs.registerMBean(new MyService(), mbeanName);

        StringMonitor monitor = new StringMonitor();
        monitor.setObservedAttribute("Status");
        monitor.setStringToCompare("ACTIVE");
        monitor.setGranularityPeriod(1000);

        System.out.println("Before adding: " + mbeanName + " observed? " + monitor.containsObservedObject(mbeanName));

        monitor.addObservedObject(mbeanName);

        boolean isObserved = monitor.containsObservedObject(mbeanName);
        System.out.println("After adding: " + mbeanName + " observed? " + isObserved);

        ObjectName anotherMbeanName = new ObjectName("com.example:type=AnotherService,name=Config");
        boolean isAnotherObserved = monitor.containsObservedObject(anotherMbeanName);
        System.out.println("Another MBean: " + anotherMbeanName + " observed? " + isAnotherObserved);

        monitor.removeObservedObject(mbeanName);
        System.out.println("After removing: " + mbeanName + " observed? " + monitor.containsObservedObject(mbeanName));

        mbs.unregisterMBean(mbeanName);
        monitor.stop();
    }

    public static class MyService implements MyServiceMBean {
        private String status = "INACTIVE";
        public String getStatus() { return status; }
        public void setStatus(String status) { this.status = status; }
    }

    public static interface MyServiceMBean {
        String getStatus();
        void setStatus(String status);
    }
}
